window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q01"]=window.__LIBQ["tien-nghich"]["q01"]||{};window.__LIBQ["tien-nghich"]["q01"]["artifacts"]={"updatedAt": "2026-06-21", "count": 30, "artifacts": [{"id": "thach-chau", "name": "Nghịch Thiên Châu", "cn": "", "aliases": ["Thạch Châu (tên ban đầu)", "Thiên Nghịch Châu", "Thiên Nghịch Châu Tử"], "category": "phap-bao", "categoryLabel": "Pháp bảo", "phamCap": "Vượt phàm — thực chất là nơi ẩn náu của cường giả lục cấp Chu Tước Quốc (Tư Đồ Nam) @c0047; điều kiện nhận chủ: ngũ hành + ≥Anh Biến kỳ", "soHuu": ["vuong-lam"], "uuTien": 100, "trangThai": "Dung hợp vĩnh viễn vào hồn phách Vương Lâm @c0102 — không còn là pháp bảo độc lập; hiện năm lá ngũ hành (Thủy+Hỏa viên mãn, Mộc nửa, thiếu Kim+Thổ) @c0117; Hỏa thuộc tính Đại viên mãn @c0116; nằm trong thức hải VL", "blurb": "Viên châu xám khắc hoa văn đám mây trắng, pháp bảo trục chính của cả bộ Tiên Nghịch. Nhặt trong xác phi điểu ở huyệt động phong nhãn (@c0008). Lai lịch thật (@c0047): Tư Đồ Nam — cường giả lục cấp Chu Tước Quốc bị truy sát, ẩn tinh hoa nguyên anh vào châu. @c0085: Mộc giai 3 lá; @c0088: lần đầu phát hắc quang; @c0112: lá thứ ba ngưng thành thực thể rồi xuất hiện phiến lá thứ năm; @c0116: tự phá ra khỏi huyệt đạo VL, hấp thu nguyên anh hỏa thuộc tính Thú tổ — đạt Hỏa thuộc tính Đại viên mãn, bề ngoài hiện hoa văn lửa đỏ rực; @c0117: trên châu năm lá — Thủy và Hỏa viên mãn, Mộc mới nửa, còn thiếu Kim và Thổ.", "detail": "To bằng nắm tay trẻ con; bề ngoài ban đầu phủ huyết nhục, lau sạch lộ màu xám với hoa văn đám mây trắng, trông rất cổ. Công năng xác nhận tới Ch.50: (1) Tiết hạt sương khi gặp ánh nắng buổi sáng — sương trị lành vết thương thể chất (@c0008–@c0009). (2) Nước ngâm châu có dược tính; hạt sương sáng sớm kết trên châu cho hiệu quả tốt nhất; tiếp theo là nước suối; máu/mồ hôi gần như vô dụng (@c0012). (3) Châu tự hấp thu hơn phân nửa hạt sương — người dùng chỉ giữ được chưa đến một phần mười (@c0012). (4) Cường hóa thể chất khi uống nước ngâm châu thường xuyên (@c0011). (5) Nước ngâm châu biến thành nước chứa linh khí sung túc (Tôn Đại Trụ xác nhận @c0016). (6) Dị biến hút nước mạnh: hút toàn bộ nước/hơi ẩm trong phạm vi rộng kể cả nước trong cơ thể người — suýt giết Trương Hổ bằng đông lạnh (@c0014). (7) Làm héo rũ thảo dược lân cận (Lam Tuyến Thảo, Tử Dạ Hoa) dù cơ chế chưa xác nhận rõ (@c0012–@c0013). (8) Số đám mây khắc trên châu tăng khi hấp thu nước: 5 (@c0008) → 6 → 7 (@c0014) → 9 (@c0020); 10 là mức cuối. (9) KHÔNG GIAN MỘNG CẢNH (@c0023): khi châu đạt đủ 10 đám mây, mây tan — lộ vài chữ số bí ẩn; châu khai mở không gian bên trong. Thời gian trong Mộng Cảnh chạy nhanh gấp 10 lần thực tại; không có linh khí tự nhiên trong đó. Mỗi lần vào cần ≥5 canh giờ liên tục — dùng cách này VL tu được ~1 năm trong 2 tháng thực (@c0024–@c0025). (10) Hiệu quả nước ngâm châu: Lộ thủy (nước lộ sớm) > Tuyết thủy (tuyết nấu tan) > Tuyền thủy (nước suối) — phân cấp xác nhận @c0031. (11) LAI LỊCH THẬT (@c0047): Thạch Châu là nơi ẩn náu của Tư Đồ Nam — cường giả lục cấp Chu Tước Quốc bị truy sát thân hủy; tinh hoa nguyên anh sót lại chui vào châu. Tư Đồ Nam dùng tinh hoa nguyên anh trợ giúp VL củng cố tu vi suốt gần 30 năm. ĐIỀU KIỆN NHẬN CHỦ: đủ ngũ hành linh căn + tu vi ≥ Anh Biến kỳ. (12) MỘC GIAI (@c0085): Châu phát triển 3 lá Mộc giai (trước đó đã có 2 lá). (13) HẮC QUANG (@c0088): Lần đầu phát hắc quang bên trong Quyết Minh Cốc — dấu hiệu Mộc giai 3 lá hoạt động. Cự Ma tộc đang tìm kiếm 'Nghịch Thiên Châu' @c0083. (14) LÁ 3 + LÁ 5 (@c0112): Khi hấp thu linh khí Phần Kim Quả và Phần Kim đằng, lá cây thứ ba ngưng thành thực thể, sau đó xuất hiện phiến lá thứ năm. (15) HỎA THUỘC TÍNH ĐẠI VIÊN MÃN (@c0116): Châu tự phá ra khỏi huyệt đạo VL, hấp thu toàn bộ nguyên anh hỏa thuộc tính của Thú tổ hỏa linh thú; đạt Hỏa thuộc tính Đại viên mãn — bề ngoài xuất hiện hoa văn lửa đỏ rực phủ ngoài hoa văn mây. (16) NĂM LÁ NGŨ HÀNH (@c0117): Trên châu hiện năm lá — thuộc tính Thủy và Hỏa đã viên mãn, Mộc mới được một nửa, còn thiếu Kim và Thổ; phải đủ ngũ hành châu mới phát uy lực chính thức, hiện vẫn chỉ dùng để khai mở Mộng Cảnh không gian.", "nguon": ["@c0008", "@c0009", "@c0010", "@c0011", "@c0012", "@c0014", "@c0016", "@c0020", "@c0023", "@c0024", "@c0025", "@c0031", "@c0046", "@c0047", "@c0083", "@c0085", "@c0088", "@c0102", "@c0110", "@c0112", "@c0116", "@c0117"]}, {"id": "that-thai-tuong-van", "name": "Thất Thải Tường Vân", "cn": "", "category": "phap-bao", "categoryLabel": "Pháp bảo", "phamCap": "Chưa xác định", "soHuu": ["ton-dai-tru"], "trangThai": "Tôn Đại Trụ đang sở hữu", "blurb": "Pháp bảo bay của Tôn Đại Trụ — vân mây bảy màu, tốc độ cực nhanh khiến phàm nhân không thở nổi. Dùng để di chuyển và lục soát phòng Vương Lâm.", "detail": "Vân/mây bảy màu lóng lánh, tốc độ di chuyển cực nhanh. Khi Vương Lâm (phàm nhân) đứng trên đó di chuyển thì hít thở không nổi. Tôn Đại Trụ dùng để đến phòng Vương Lâm và kết hợp thần thức lục soát tịch thu đồ vật (@c0016). Trước đó hắn bay bằng 'đám mây bảy màu' để di chuyển trong tông môn (@c0013).", "nguon": ["@c0013", "@c0016"]}, {"id": "ho-lo-nuoc-linh-khi", "name": "Hồ Lô (nước linh khí)", "cn": "", "category": "vat-chua", "categoryLabel": "Vật chứa", "phamCap": "Phàm vật (hồ lô hoang dại) nhưng nội dung bên trong có giá trị tu luyện", "soHuu": [], "trangThai": "VL còn ba hồ lô sương sớm (sương đông đặc) trong túi trữ vật (@c0020); hồ lô bị tịch thu (@c0016) đã cạn linh khí", "blurb": "Hồ lô hoang dại Vương Lâm tìm trong núi, dùng đựng nước suối ngâm Thạch Châu tạo thành nước chứa linh khí sung túc. Bị Tôn Đại Trụ phát hiện và tịch thu; VL sau lấy lại ba hồ lô đựng sương sớm.", "detail": "Vương Lâm tìm hồ lô hoang dại trong núi để đựng và phân loại các loại hạt sương/nước suối ngâm châu. Nước suối ngâm Thạch Châu bên trong chứa linh khí cực sung túc — phàm nhân uống không hấp thụ được linh khí nhưng tinh thần thoải mái; nếu dùng luyện đan dược thì hiệu quả rất tốt (@c0016). Tôn Đại Trụ ngửi nước trong hồ lô thì 'sắc mặt đại biến', tra hỏi gắt nguồn gốc (@c0016). Linh khí trong hồ lô bị tịch thu cạn dần và mất hết trong ~1 tháng (@c0019). Ba hồ lô sương sớm VL lấy lại: sương bên trong đã đông đặc; VL dự định dùng để ép đám mây thứ mười trên châu (@c0020).", "nguon": ["@c0012", "@c0016", "@c0019", "@c0020"]}, {"id": "thien-ly-phu", "name": "Thiên Lý Phù", "cn": "", "category": "tien-phu", "categoryLabel": "Tiên phù", "phamCap": "Hạ phẩm (rất thấp kém trong hệ tu tiên)", "soHuu": ["vuong-lam", "hang-nhac-phai", "vuong-hao"], "trangThai": "VL đã dùng hết trong phạm vi Ch.12–14; Lưu sư huynh tặng thêm một tờ (@c0015)", "blurb": "Tiên phù di chuyển cấp thấp nhất: dán ở đùi để tăng tốc độ cho phàm nhân, phát bạch quang chói mắt, dã thú thấy tránh xa. Tôn trưởng lão cấp cho ký danh đệ tử về thăm nhà.", "detail": "Thiên Lý Phù còn gọi là tiên phù, Tham Thân phù, Tham Thân tiên phù hay cuộn giấy vàng; tuy là đồ của tiên nhân nhưng được đánh giá là loại tiên phù vô cùng thấp kém. Thoạt nhìn có bề ngoài giống hệt một tờ giấy vàng bình thường, không có gì hiếm thấy. Được Hằng Nhạc phái phát cho các ký danh đệ tử mỗi khi họ xin về nhà thăm người thân; nguồn không đề cập ai luyện chế. Môn phái dùng nó với mục đích để đệ tử về quê thể hiện chút tiên gia pháp thuật, hấp dẫn thêm trẻ đến trắc thí nhập môn. Công năng: dán lên đùi làm tăng tốc độ người dùng, đặc biệt có tác dụng đề cao tốc độ với phàm nhân; ưu điểm duy nhất là cách dùng đơn giản, mỗi tấm tiêu chuẩn chỉ dùng được hai lần. Dù thấp kém nhưng có giá trị trao đổi: đệ tử nội môn tích cóp để giao dịch đổi đồ vật, các ký danh đệ tử xem là vật rất quý, về sau dùng như một loại tiền tệ (200 tấm đổi một viên Hóa Hình Hóa Thanh Đan). Tồn tại một biến thể đặc biệt là cuộn giấy vàng, bề ngoài giống Tham Thân tiên phù nhưng chất liệu, màu sắc và nét bút đều vượt xa, ẩn chứa linh khí vượt trội và toát hơi thở nguy hiểm, được xem là bảo bối thực sự; đây là vật do Trương Hổ để lại cho Vương Lâm, không phải đoạt từ thi thể.\n\nDIỄN BIẾN:\n- Một người phụ trách việc của ký danh đệ tử ném một tờ Thiên Lý Phù từ cửa sổ ra cho Vương Lâm, yêu cầu đi nhanh về sớm trong ba ngày. Vương Lâm nhặt lên, thận trọng cất vào trong ngực; do không biết cách điều chỉnh tốc độ của tiên phù và sợ bỏ lỡ sinh nhật cha nên quyết định chạy đi suốt đêm. Các đệ tử nội môn và ký danh đệ tử không ngừng tích cóp, thu nhặt Thiên Lý Phù để đem ra ngoài giao dịch hoặc giữ làm tài sản riêng. (@c0011)\n- Vương Lâm được Trương Hổ tặng một cuộn giấy vàng tiên phù đặc biệt (không phải đoạt từ thi thể). Ban đầu tưởng là Tham Thân tiên phù bình thường, nhưng sau khi quan sát kỹ hắn phát hiện nó ẩn chứa linh khí vượt xa Tham Thân phù cùng hơi thở nguy hiểm, khẳng định là bảo bối nhưng chưa rõ công năng. Vì từng suýt chết do uống Hạ Lộ thủy, Vương Lâm rất cảnh giác với đồ của tiên nhân nên không dám dùng bừa bãi, đành cất vào túi trữ vật để dành sau này tìm hiểu. (@c0027)\n- Sau khi được phân công làm ở chỗ tạp vụ, trong vài tháng Vương Lâm đã nhận hối lộ và tích được gần 500 tấm tiên phù. Vương Hạo tìm đến hỏi mượn 200 tấm để mua Hóa Hình Hóa Thanh Đan từ chủ nhân của mình, dùng đan làm điều kiện tham gia giao dịch hội ngầm của đệ tử nội môn trước kỳ so tài cuối năm. Vương Lâm thấy giao dịch hội thú vị nên lật tay lấy ra 400 tấm tiên phù (gộp mỗi 100 thành một phần) đưa Vương Hạo, nhờ mua luôn cho mình một viên Hóa Hình Hóa Thanh Đan để cùng đi xem; hắn rất coi trọng vì hy vọng đoạt được khẩu quyết Ngưng Khí phía sau. (@c0031)", "nguon": ["@c0012", "@c0013", "@c0015"], "aliases": ["tiên phù", "Tham Thân phù", "Tham Thân tiên phù", "cuộn giấy vàng"]}, {"id": "tham-than-tien-phu", "name": "Tham Thân tiên phù", "cn": "", "category": "tien-phu", "categoryLabel": "Tiên phù", "phamCap": "Hạ phẩm (tiêu hao dùng một lần)", "soHuu": ["vuong-lam"], "trangThai": "Vương Lâm thu được nhiều từ đệ tử ký danh (@c0029); cho Vương Hạo mượn một tờ (@c0030)", "blurb": "Tiên phù hỗ trợ tu luyện; được đệ tử ký danh dùng làm vật đút lót quản sự khu tạp vụ để đổi lấy suất ký danh ưu tiên.", "detail": "Loại phù hỗ trợ tu luyện thể thất thường được dùng ở cấp độ ký danh đệ tử Hằng Nhạc Phái. Các đệ tử ký danh dùng để đút lót Vương Lâm đổi lấy vị trí ưu tiên trong danh sách ký danh (@c0029). Vương Hạo sau đó đến mượn một tờ từ VL để hỗ trợ tu luyện đột phá Ngưng Khí tầng 1 (@c0030). Chi tiết hiệu quả cụ thể chưa được nguyên tác mô tả rõ.", "nguon": ["@c0029", "@c0030"]}, {"id": "cuon-giay-vang", "name": "Cuộn giấy vàng bí ẩn", "cn": "", "category": "khac", "categoryLabel": "Bí ẩn", "phamCap": "Chưa xác định", "soHuu": ["vuong-lam"], "trangThai": "Vương Lâm đang sở hữu (@c0026); nội dung chưa được giải mã (@c0027)", "blurb": "Cuộn giấy vàng VL nhặt được tại hiện trường vụ Trương Hổ giết Lưu sư huynh. Lai lịch và nội dung bí ẩn, chưa hé lộ.", "detail": "Vương Lâm tình cờ nhặt được cuộn giấy này tại hiện trường vụ Trương Hổ giết Lưu sư huynh rồi bỏ trốn (@c0026). VL giữ cuộn giấy nhưng tới Ch.27 chưa rõ nội dung bên trong (@c0027). Lai lịch thật và tác dụng chưa được nguyên tác giải thích.", "nguon": ["@c0026", "@c0027"]}, {"id": "cu-phu", "name": "Cự Phú", "cn": "", "category": "phap-bao", "categoryLabel": "Pháp bảo — Phi kiếm", "phamCap": "Di vật sư tổ (cấp cao, cấm buôn bán)", "soHuu": ["vuong-lam"], "trangThai": "Vương Lâm đang sở hữu (lấy từ Kiếm Linh Các @c0039)", "blurb": "Phi kiếm đệ nhất Triệu quốc — khối kim loại to bằng cẳng tay, mạ hoàng kim, khảm 2 viên kim cương to bằng hạt đậu ở tay cầm, tua bằng vàng. Di vật sư tổ Hằng Nhạc Phái ngàn năm, cấm buôn bán.", "detail": "Cự Phú là phi kiếm đệ nhất trong số phi kiếm của Hằng Nhạc Phái, cất trong Kiếm Linh Các ngàn năm nay. Hình dáng: khối kim loại to bằng cẳng tay người lớn, dài khoảng một xích; mạ hoàng kim bóng loáng, tay cầm khảm 2 viên kim cương to bằng hạt đậu, đuôi chuôi kết tua vàng. Di vật sư tổ Hằng Nhạc Phái (thủy tổ), quy định cấm buôn bán. Kiếm khí của Cự Phú 'tự chọn người xứng đáng' — gã mập trông coi theo VL vào cấm chế bị đánh văng hộc máu, trong khi VL vào hoàn toàn tự nhiên (@c0039). Tôn Đại Trụ kinh ngạc vì VL dám chọn vật này, khen có đảm lược (@c0039).", "nguon": ["@c0039"]}, {"id": "song-nguyet-hoan", "name": "Song Nguyệt Hoàn", "cn": "", "category": "phap-bao", "categoryLabel": "Pháp bảo", "phamCap": "Di vật tiền bối 300 năm (cấp cao)", "soHuu": [], "trangThai": "Giải thưởng giải nhất tỷ thí cuối năm Hằng Nhạc Phái (@c0034); người giành được chưa xác định trong nghiên cứu tới Ch.40", "blurb": "Trọng bảo giải nhất tỷ thí cuối năm Hằng Nhạc Phái — di vật tiền bối 300 năm, vừa công vừa thủ. Tiết lộ @c0034 khi chưởng môn công bố kế hoạch tập huấn chuẩn bị cho đại hội Huyền Đạo Tông.", "detail": "Song Nguyệt Hoàn là pháp bảo hai chức năng: tấn công và phòng thủ. Di vật tiền bối 300 năm trước. Được đặt làm giải nhất cuộc tỷ thí nội bộ cuối năm của Hằng Nhạc Phái — cuộc tỷ thí mà Trương sư huynh (hắc y, tầng 5) giành chiến thắng theo ghi nhận @c0034. Chi tiết cơ chế sử dụng chưa được nguyên tác mô tả.", "nguon": ["@c0034"]}, {"id": "tu-nhac-tien-kiem", "name": "Tử Nhạc Tiên Kiếm", "cn": "", "category": "phap-bao", "categoryLabel": "Pháp bảo — Tiên kiếm", "phamCap": "Cấp chưởng môn (Nguyên Anh kỳ hoặc tương đương)", "soHuu": ["hoang-long-chan-nhan"], "trangThai": "Bị Phác Nam Tử đoạt, giao cho Âu Dương @c0054; Hoàng Long ai điếu 'kiếm còn người còn' @c0056", "blurb": "Bảo kiếm của Hoàng Long chân nhân — chưởng môn Hằng Nhạc Phái. Chứa Long Hồn bên trong, khi thi triển hóa thành tử long uy mãnh. Bị Phác Nam Tử đoạt lấy khi Hằng Nhạc sơn môn thất thủ @c0054.", "detail": "Tử Nhạc Tiên Kiếm là bảo kiếm của Hoàng Long chân nhân, chưởng môn Hằng Nhạc Phái. Khi kích hoạt, Long Hồn bên trong hóa thành tử long dài vài trượng — đủ sức uy hiếp và cân bằng với Thiên Túc Ngô Công (rết khổng lồ ~100m, hộ sơn linh thú Huyền Đạo Tông) @c0040. Khi Phác Nam Tử (Nguyên Anh kỳ, Huyền Đạo Tông) tấn công Hằng Nhạc, kiếm bị đoạt và giao cho Âu Dương — khi được tung ra, một cự long tử sắc xuất hiện @c0054. Hoàng Long ai điếu 'kiếm còn người còn' @c0056.", "nguon": ["@c0040", "@c0054", "@c0056"]}, {"id": "tieu-kiem-that-thai", "name": "Tiểu Kiếm thất thải", "cn": "", "category": "phap-bao", "categoryLabel": "Pháp bảo — Phi kiếm", "phamCap": "Thất thải (7 màu — cấp cao trong phi kiếm)", "soHuu": ["ton-dai-tru"], "trangThai": "Tôn Đại Trụ đang sở hữu (@c0038)", "blurb": "Phi kiếm bảy màu bảy thải của Tôn Đại Trụ. Lóng lánh bảy sắc, bay nhanh đến mức người phàm không thở nổi. Tôn Đại Trụ dùng để di chuyển và giới thiệu với Vương Lâm khi nhận làm đệ tử chân chính.", "detail": "Tiểu Kiếm thất thải là pháp bảo phi kiếm cá nhân của Tôn Đại Trụ, tức chính là 'đám mây bảy màu' mà lão hay sử dụng để bay. Tôn Đại Trụ giới thiệu với Vương Lâm và khoe uy lực @c0038. Đây cũng chính là Thất Thải Tường Vân mà nguyên tác từng đề cập ở @c0013–@c0016 khi Tôn di chuyển trong môn phái.", "nguon": ["@c0013", "@c0016", "@c0038"]}, {"id": "thien-tuc-ngo-cong", "name": "Thiên Túc Ngô Công", "cn": "", "category": "linh-thu", "categoryLabel": "Linh thú", "phamCap": "Hộ sơn linh thú (cấp Kết Đan hoặc cao hơn)", "soHuu": ["huyen-dao-tong"], "trangThai": "Huyền Đạo Tông sử dụng; VL đã lấy dịch độc @c0049 và Ngô Công được trả lại", "blurb": "Linh thú hộ sơn của Huyền Đạo Tông — rết khổng lồ trăm chân, thân dài hàng trượng, xuất hiện khi đoàn Huyền Đạo Tông đến Hằng Nhạc Phái gây khiếp đảm toàn môn. Bị Tử Nhạc Tiên Kiếm uy hiếp (@c0040). Dịch độc màu đen của nó mạnh theo tỉ lệ kích thước đầu (@c0042); VL lấy được dịch độc tại Ch.49 để trị bệnh phong hàn cho phụ thân.", "detail": "Thiên Túc Ngô Công là linh thú hộ sơn của Huyền Đạo Tông. Hình dáng: rết khổng lồ trăm chân, thân dài ước tính cỡ trăm trượng; xuất hiện theo đoàn khách Huyền Đạo Tông đến Hằng Nhạc Phái @c0039. Hoàng Long chân nhân thi triển Tử Nhạc Tiên Kiếm hóa tử long để uy hiếp — hai bên cân bằng @c0040. Bí pháp khống chế là vật trao đổi trong cược tỷ thí @c0040. VL một mình vào chuồng Ngô Công @c0041: bị Ngô Công phun hàn khí nhưng VL vận linh lực hóa giải dễ dàng; Ngô Công kinh ngạc. VL quan sát cơ chế độc @c0042: Ngô Công phun hàn khí + khạc khí đen độc hại; độc tỉ lệ thuận kích thước đầu; khí đen làm tan thú nhỏ thành vũng máu. Ch.49: VL vận Dẫn Lực thuật hóa hai bàn tay hữu hình, khống chế Ngô Công ép thổ dịch độc màu đen vào bình ngọc; Ngô Công bị kiểm soát dù Âu Dương can thiệp. VL thu dịch độc, đổi bình nước sông hóa giải xung đột (@c0049).", "nguon": ["@c0039", "@c0040", "@c0041", "@c0042", "@c0049"]}, {"id": "tao-hoa-dan", "name": "Tạo Hóa Đan", "cn": "", "category": "dan-duoc", "categoryLabel": "Đan dược", "phamCap": "Trân quý (giá 2000 viên Đoạt Linh Đan — không ai mua nổi @c0033)", "soHuu": [], "trangThai": "Lưu thông trong giới tu chân; từng rao bán ở giao dịch hội @c0032", "blurb": "Đan dược tăng tốc hấp thu linh khí: dùng liên tục 2 tháng, linh khí hấp thu gấp vài lần bình thường. Được rao bán tại giao dịch hội bí mật của nội môn đệ tử Hằng Nhạc Phái — giá 2000 Đoạt Linh Đan, không ai mua nổi.", "detail": "Tạo Hóa Đan: uống liên tục 2 tháng, trong thời gian đó tốc độ hấp thu linh khí tăng vài lần so với bình thường (@c0032). Giá trị rất cao — tại giao dịch hội đẩy lên 2000 viên Đoạt Linh Đan, toàn bộ người tham dự không ai có đủ (@c0033). Cơ chế hoạt động và nguồn gốc chưa được nguyên tác mô tả chi tiết. Liên quan đến hệ thống thăng cấp đặc biệt: hắc y được thưởng +1 viên, tử y được thưởng +2 viên khi thăng cấp @c0032.", "nguon": ["@c0032", "@c0033"]}, {"id": "hoa-hinh-hoa-thanh-dan", "name": "Hóa Hình Hóa Thanh Đan", "cn": "", "category": "dan-duoc", "categoryLabel": "Đan dược", "phamCap": "Hạ phẩm (giá 200 tờ tiên phù)", "soHuu": [], "trangThai": "Lưu thông; Vương Hạo mua 2 viên dùng làm vé vào giao dịch hội @c0031–@c0032", "blurb": "Đan dược che giấu thân phận: uống vào thay đổi hình dáng và âm thanh, che giấu trước mắt người dưới Trúc Cơ. Người Trúc Cơ kỳ trở lên vẫn có thể nhìn xuyên qua.", "detail": "Hóa Hình Hóa Thanh Đan dùng để thay đổi diện mạo và giọng nói tạm thời — che giấu thân phận khỏi những người tu vi dưới Trúc Cơ. Người đạt Trúc Cơ kỳ trở lên vẫn nhìn thấu được (@c0031). Giá tiêu chuẩn: 200 tờ tiên phù/viên; Vương Hạo mua 2 viên làm 'vé' vào giao dịch hội (@c0031). VL và Vương Hạo đều uống trước khi vào hội @c0032. Nhờ đó VL không bị Trương Cuồng nhận mặt tại giao dịch hội @c0033–@c0035.", "nguon": ["@c0031", "@c0032"]}, {"id": "doat-linh-dan", "name": "Đoạt Linh Đan", "cn": "", "category": "dan-duoc", "categoryLabel": "Đan dược", "phamCap": "Phổ thông (đơn vị tiêu chuẩn giao dịch trong Hằng Nhạc Phái)", "soHuu": ["vuong-lam"], "trangThai": "Vương Lâm nhận định kỳ; Trương Cuồng phát 100 viên/người/năm tại Hậu Sơn @c0035", "blurb": "Đan dược hỗ trợ tu luyện phổ thông, đồng thời là đơn vị tiêu chuẩn trong giao dịch nội bộ Hằng Nhạc Phái. Phát định kỳ cho đệ tử nội môn; tại Hậu Sơn Trương Cuồng phát 100 viên/người/năm.", "detail": "Đoạt Linh Đan là đan dược hỗ trợ tu luyện cơ bản của Hằng Nhạc Phái. Ngoài công dụng tu luyện, nó còn là đơn vị đo giá trị chuẩn trong các giao dịch nội bộ tu chân giới (@c0032). Tôn Đại Trụ cấp cho VL định kỳ (số lượng không xác định). Tại Hậu Sơn trong 4 năm tập huấn: Trương Cuồng phát 50 lọ × 100 viên/người, tức 100 viên/người/năm (@c0035). VL sử dụng loại này thường xuyên trong tu luyện.", "nguon": ["@c0017", "@c0032", "@c0035"]}, {"id": "phich-lich-dan", "name": "Phích Lịch Đạn", "cn": "", "category": "dan-duoc", "categoryLabel": "Đan dược — Vũ khí", "phamCap": "Hạ phẩm (có thể mua tại chợ; Lý Sơn bán công khai @c0044)", "soHuu": ["ly-son", "vuong-lam"], "trangThai": "VL mua 3 viên @c0045; đã dùng một số trong tỷ thí @c0048", "blurb": "Đạn nổ bán công khai tại chợ của Lý Sơn (Huyền Đạo Tông). Thực chất là đạn gian: không tự nổ — chỉ nổ khi Lý Sơn ngầm phóng linh khí ba động kích hoạt. VL phát hiện bí mật này qua thần thức (@c0044–@c0045), nuốt đạo thần thức Lý Sơn bên trong để tự mình kích nổ (@c0046).", "detail": "Phích Lịch Đạn ngoài mặt rao bán như vũ khí nổ thông thường. Bí mật: bên trong mỗi viên có đạo thần thức của Lý Sơn; Lý Sơn phóng linh khí ba động từ xa mới kích hoạt nổ — không có Lý Sơn can thiệp thì đạn không nổ (@c0044). VL dùng thần thức phát hiện cơ chế này (@c0044). Mua 3 viên từ Lý Sơn (@c0045). Sau đó VL bao thần thức vào đạn, phát hiện đạo thần thức Lý Sơn bên trong, nuốt đạo thần thức đó — từ đó VL tự kích nổ được (@c0046). Dùng trong tỷ thí hạ Chu Bằng 3 lần và Dương Nghị (@c0048).", "nguon": ["@c0044", "@c0045", "@c0046", "@c0048"]}, {"id": "dich-doc-ngo-cong", "name": "Dịch Độc Thiên Túc Ngô Công", "cn": "", "category": "nguyen-lieu", "categoryLabel": "Nguyên liệu đặc biệt", "phamCap": "Quý hiếm — lấy trực tiếp từ linh thú cấp cao", "soHuu": ["vuong-lam"], "trangThai": "Vương Lâm thu được vào bình ngọc @c0049", "blurb": "Dịch độc màu đen do Thiên Túc Ngô Công khạc ra — tan thú nhỏ thành vũng máu. Độc tỉ lệ thuận kích thước đầu (@c0042). VL lấy để trị bệnh phong hàn nhập thể cho phụ thân (@c0043, @c0049). Thu được bằng cách ép Ngô Công bằng Dẫn Lực thuật, bỏ vào bình ngọc.", "detail": "Ngô Công khạc khí đen sau khi phun hàn khí — khí đen làm tan con thú nhỏ thành vũng máu (@c0042). Độc tố tỉ lệ thuận kích thước đầu Ngô Công (@c0042). VL muốn lấy dịch độc này khi nghe Vương Hạo kể về bệnh phong hàn nhập thể của phụ thân (@c0043). Ch.49: VL vận Dẫn Lực thuật hóa hai bàn tay hữu hình, khống chế Ngô Công ép thổ dịch độc màu đen vào bình ngọc; thu được trước sự can thiệp của Âu Dương (@c0049). Công dụng trị phong hàn chưa được xác nhận trong nguyên tác (là mục đích của VL).", "nguon": ["@c0042", "@c0043", "@c0049"]}, {"id": "nhan-tho-dan", "name": "Nhân Thọ Đan", "cn": "", "category": "dan-duoc", "categoryLabel": "Đan dược — Tà đạo", "phamCap": "Bí ẩn (luyện bằng dược lô người sống)", "soHuu": ["lu-van-kiet"], "trangThai": "Lữ Vân Kiệt đang luyện; Vương Hạo được cứu trước khi hoàn thành @c0050", "blurb": "Đan dược tà đạo — luyện bằng cách dùng người làm dược lô (ép tu Lô Hỏa Khai Đỉnh Đại Pháp). Mục đích: đổi thêm thọ mệnh cho người tu luyện bị kẹt cảnh giới. Lữ Vân Kiệt luyện để kéo dài thọ mệnh do bị kẹt tầng 6 suốt 25 năm. (@c0043)", "detail": "Nhân Thọ Đan cần nguyên liệu đặc biệt: người làm dược lô tu Lô Hỏa Khai Đỉnh Đại Pháp — tích năng lượng sống rồi bị thu hết. Người làm dược lô chỉ còn ~1 năm sống (@c0043). Lữ Vân Kiệt bị kẹt tầng 6 suốt 25 năm, lên kế hoạch dùng Vương Hạo làm dược lô. Vương Hạo được VL cứu trước khi quá trình hoàn tất (@c0050). Hồng Kiểm lão giả xác nhận Lô Hỏa Khai Đỉnh là thật (@c0050). Công dụng Nhân Thọ Đan chưa được mô tả chi tiết — chỉ biết dùng để kéo dài thọ mệnh.", "nguon": ["@c0043", "@c0050"]}, {"id": "tam-thi-tuyen-trung-thao", "name": "Tam Thi Tuyến Trùng thảo", "cn": "", "category": "nguyen-lieu", "categoryLabel": "Nguyên liệu — Thảo dược độc", "phamCap": "Đặc dị (không màu không mùi, 100% khống chế người dưới Trúc Cơ)", "soHuu": ["ton-dai-tru"], "trangThai": "Tôn Đại Trụ dùng để âm mưu khống chế VL @c0051; bị phá giác, Tôn Đại Trụ chết", "blurb": "Thảo dược đặc biệt không màu không mùi, tỷ lệ khống chế 100% đối với người dưới Trúc Cơ kỳ. Nguyên liệu để luyện Khôi Lỗi. Tôn Đại Trụ dùng để âm mưu biến VL thành con rối vĩnh viễn; bị phát giác, dẫn đến Tôn Đại Trụ bị giết. (@c0051)", "detail": "Tam Thi Tuyến Trùng thảo là thảo dược cực kỳ đặc biệt: không màu, không mùi, khiến người khó phát hiện. Tỷ lệ khống chế người dưới Trúc Cơ kỳ đạt 100% — người bị dùng sẽ mất ý thức tự chủ, bị điều khiển vĩnh viễn. Đây cũng là nguyên liệu để luyện Khôi Lỗi (@c0051). Tôn Đại Trụ dùng thảo dược này âm mưu biến VL thành con rối, nhưng bị VL phát giác — dẫn đến trận phản sát, Tôn chết (@c0051).", "nguon": ["@c0051"]}, {"id": "hoa-linh-thao", "name": "Hóa Linh thảo", "cn": "", "category": "nguyen-lieu", "categoryLabel": "Nguyên liệu — Thảo dược", "phamCap": "Chưa xác định", "soHuu": ["ton-dai-tru"], "trangThai": "Tôn Đại Trụ dùng để tán công VL (ức chế tu vi) @c0051", "blurb": "Thảo dược có tác dụng làm phân tán linh khí — gây 'tán công', ức chế khả năng tu luyện của đối tượng. Tôn Đại Trụ dùng để kìm hãm VL trước khi tiến hành kế hoạch Tam Thi Tuyến Trùng thảo. (@c0051)", "detail": "Hóa Linh thảo khiến linh khí trong người đối tượng phân tán, không tập trung được — hiệu quả tu luyện và vận công bị suy giảm đáng kể. Tôn Đại Trụ dùng để ức chế VL kết hợp với âm mưu Tam Thi Tuyến Trùng thảo (@c0051). Chi tiết cơ chế và nguồn gốc chưa được nguyên tác mô tả thêm.", "nguon": ["@c0051"]}, {"id": "lam-viem-ma-hoa", "name": "Lam Viêm Ma Hỏa", "cn": "", "category": "phap-bao", "categoryLabel": "Pháp bảo — Dị hỏa", "phamCap": "Dị hỏa (tế luyện từ kim đan Kết Đan kỳ Chánh Đạo Liên Minh)", "soHuu": ["da-tu-tai"], "trangThai": "Dạ Tự Tại đang sở hữu; đặt trong huyệt động cột đá Thi Âm tông (5 hỏa cầu @c0080); Mộc Ngung tu luyện bằng khí xanh biếc từ hỏa cầu này @c0080", "blurb": "Dị hỏa màu lam xanh biếc của Thi Âm tông. Tế luyện từ kim đan cao thủ Kết Đan kỳ Chánh Đạo Liên Minh. Đặt thành 5 hỏa cầu trong huyệt động cột đá để đệ tử tu luyện hấp thụ qua thất khiếu. Khi Dạ Tự Tại xuất hiện, 4 hỏa cầu tối sầm tỏa khói xanh. (@c0080)", "detail": "Lam Viêm Ma Hỏa được nhắc lần đầu @c0080: Mộc Ngung đang ngồi hấp thụ khí xanh biếc từ hỏa cầu Lam Viêm Ma Hỏa qua thất khiếu trong huyệt động cột đá. Khi Dạ Tự Tại xuất hiện, 4 hỏa cầu tối sầm và tỏa khói xanh — bóng người hư ảo Dạ Tự Tại hiện ra từ hỏa cầu. Tư Đồ Nam @c0052 nhắc về dị hỏa cực kỳ bí ẩn Thi Âm tông (bối cảnh khác nhưng có thể đây là cùng một vật). Chánh Đạo Liên Minh đã bị Thi Âm tông đoạt lấy dị hỏa từ kim đan cao thủ Kết Đan — cơ chế thu thập dã man của tông phái tà đạo.", "nguon": ["@c0052", "@c0080"]}, {"id": "dan-duoc", "name": "Đan dược", "cn": "", "aliases": ["nội đan", "linh đan", "dược hoàn", "Tạo Hóa Đan", "Hóa Hình Hóa Thanh Đan", "Đoạt Linh Đan"], "category": "phap-bao", "categoryLabel": "Pháp bảo", "phamCap": "", "soHuu": ["vuong-lam", "vuong-hao"], "blurb": "Đan dược là những viên thuốc hoặc hạt trân quý, được luyện chế thành phẩm từ các loại thảo dược chứa rất nhiều linh khí.", "detail": "Đan dược là những viên thuốc hoặc hạt trân quý, được luyện chế thành phẩm từ các loại thảo dược chứa rất nhiều linh khí. Đan dược môn phái thường được bào chế tại các đan phòng do sư huynh hoặc cao thủ khống chế. Linh đan/dược hoàn thông thường có hình dạng long lanh trong suốt; khi nuốt vào, dược lực sinh ra luồng khí nóng lưu chuyển khắp cơ thể, mang lại cảm giác thư thái dễ chịu và làm tan biến cảm giác đói, cung cấp linh khí giống thang thuốc thảo dược. Tạo Hóa Đan là dược vật cực kỳ trân quý: khi ăn, dược lực đọng lại trong cơ thể suốt 2 tháng, tốc độ hấp thụ linh khí tăng gấp mấy lần — báu vật đám đệ tử môn nội ao ước. Hóa Hình Hóa Thanh Đan có màu xanh biếc; khi ăn, một làn sương mù màu đen đậm đặc tản ra bao phủ toàn thân, thay đổi giọng nói thành khàn khàn và che giấu hoàn toàn tu vi cùng nhân dạng, khiến thần thức người khác không thể thăm dò, trừ khi đối phương đạt Trúc Cơ kỳ. Đoạt Linh Đan là đan dược thành phẩm có sẵn linh khí, dùng bằng cách nuốt; một viên được lấy làm hệ quy chiếu giá trị (một giọt chất lỏng thần bí của Vương Lâm được so ngang một viên Đoạt Linh Đan). Tại giao dịch hội ngầm, linh đan và Đoạt Linh Đan mang đặc điểm như loại tiền tệ giá trị cao, dùng để định giá, trả giá và trao đổi pháp bảo, tiên phù, ngọc giản, khẩu quyết tu luyện.\n\nDIỄN BIẾN:\n- Tại khu vực ngoài đan phòng của tam sư huynh, trong lúc chờ linh đan ra lò, Vương Hạo nhân lúc mọi người không chú ý đã lén nhét vào tay Vương Lâm 3 viên dược hoàn (linh đan). Buổi tối, khi đan phòng mở cửa, Vương Hạo bưng khay ra chia đan dược, Vương Lâm được nhận thêm phần chính thức của mình là 1 viên. Tổng cộng Vương Lâm sở hữu 4 viên linh đan và cất giấu vào túi trữ vật. (@c0013)\n- Vương Lâm quyết định lấy từ trong túi trữ vật ra 1 viên linh đan để nuốt thử. Hắn cảm nhận được khí nóng và sự dễ chịu lan tỏa, nhưng đáng tiếc là vẫn không thể ngưng tụ được linh khí để tu luyện. (@c0022)\n- Vương Hạo tiết lộ Vương Trác được sư phụ xin cho một lô Tạo Hóa Đan để ăn, nhờ đó tốc độ tu luyện tăng vọt, sắp chạm đến Ngưng Khí tầng 2. Cùng lúc, Vương Hạo ngỏ ý mượn Vương Lâm 200 tấm tiên phù để mua 1 viên Hóa Hình Hóa Thanh Đan nhằm lấy tư cách tham gia giao dịch hội ngầm. Vương Lâm đồng ý và đưa luôn 400 tấm tiên phù để mua 2 viên cho cả hai người. (@c0031)\n- Trên đường tham gia giao dịch hội, Vương Hạo đưa cho Vương Lâm 1 viên Hóa Hình Hóa Thanh Đan màu xanh biếc. Cả hai cùng nuốt đan dược, lập tức bị sương mù đen bao phủ, thay đổi giọng nói và che giấu thành công thân phận để bước vào bãi đất trống. Một người rao bán hạ giai ngọc phù đổi 10 khỏa linh đan, bị người khác trả vọt lên 12 khỏa. Thuật pháp giấu tu vi bị chê vô dụng nhưng đắt 5 khỏa linh đan; chỉ Vương Lâm bước ra đổi. Khi rao Tạo Hóa Đan tự ra giá, nhiều người trả cao: Vương Hạo hô 20 khỏa Đoạt Linh Đan; có người trả 2000 tiên phù; 30 khỏa Đoạt Linh Đan + 500 tiên phù; combo hạ giai ngọc phù + phi kiếm + 10 khỏa Đoạt Linh Đan + 500 tiên phù. (@c0032)\n- Tại giao dịch hội, đan dược trở thành đơn vị trao đổi sôi nổi: một người đòi 10 khỏa linh đan đổi ngọc phù hạ giai, lập tức có người nâng lên 12 khỏa. Một người rao bán pháp thuật che giấu tu vi giá 5 khỏa linh đan; Vương Lâm bước lên đồng ý dùng 5 khỏa linh đan đổi lấy ngọc giản thuật pháp này. Một người (Vương Lâm nghĩ thầm tám chín phần mười là Vương Trác nhưng không dám khẳng định) mang 1 viên Tạo Hóa Đan ra rao bán tự do; cả hội tranh giành quyết liệt, giá đẩy từ 20 khỏa Đoạt Linh Đan lên 500 khỏa cộng phi kiếm/tiên phù. Vương Hạo hét giá cực hạn 230 khỏa Đoạt Linh Đan nhưng người bán từ chối, cuồng ngạo tuyên bố ít nhất 2000 viên Đoạt Linh Đan mới đổi, khiến giao dịch bị hủy. Vương Lâm rao bán chất lỏng thần bí, giới thiệu 1 giọt sánh bằng 1 viên Đoạt Linh Đan, để đổi khẩu quyết Ngưng Khí kỳ; mọi người động tâm vì Đoạt Linh Đan chỉ nuốt được, còn chất lỏng này có thể luyện đan hoặc luyện pháp bảo. (@c0033)", "nguon": ["@c0003", "@c0013", "@c0022", "@c0031", "@c0032", "@c0033"]}, {"id": "hat-chau-than-bi", "name": "Hạt châu thần bí", "cn": "", "aliases": [], "category": "phap-bao", "categoryLabel": "Pháp bảo", "phamCap": "", "soHuu": ["vuong-lam"], "blurb": "Pháp bảo Vương Lâm vô tình nhặt được trong xác một con phi điểu.", "detail": "Pháp bảo Vương Lâm vô tình nhặt được trong xác một con phi điểu. Hạt châu có thể tự rung lên, bay lơ lửng và hấp thu mạnh mẽ toàn bộ nước mưa, hơi ẩm, sương mù xung quanh; khi hấp thu đủ nước, các hình khắc đám mây trên bề mặt gia tăng số lượng (từ 5 lên 7, rồi lên 9 đám mây). Khi ngâm vào tuyền thủy hoặc lộ thủy, nó chuyển hóa nước thường thành nước chứa lượng linh khí khổng lồ; uống loại nước này giúp cơ thể thư thái, tiêu trừ cảm giác đói, cải tạo cơ thể và gia tăng linh khí vô tận, hiệu quả vượt xa đan dược thông thường. Hạt châu còn cho phép người sở hữu tiến nhập 'mộng cảnh giới' tối đa 3 lần mỗi ngày, mỗi lần kéo dài hơn 50 giờ (tương đương 6 ngày), kéo dài thời gian tu luyện thực tế gấp nhiều lần (2 tháng bên ngoài tương đương 1 năm tu luyện bên trong). Khi uống nhiều lộ thủy, linh khí ngưng tụ vượt tốc độ tiêu tan khiến cơ thể Vương Lâm đau nhức, mạch máu nổi căng phồng sắp vỡ; hắn nảy ra sáng kiến hít thở ngược (ba dài một ngắn) để giải tỏa linh khí — khởi nguồn của tán công. Khí độc do tán công phát tán không bị hạt châu hấp thụ mà tự tiêu tan, còn linh khí phát ra thì bị hạt châu hấp thụ.\n\nDIỄN BIẾN:\n- Trong lúc hoảng loạn và đói khát, Vương Lâm ăn xác một con phi điểu và vô tình nhặt được 'Hạt châu thần bí' bên trong. Trong một đêm mưa bão làm ướt sũng phòng ở, hắn lấy hạt châu đặt trước ngực; hạt châu bất ngờ kích hoạt, bay lơ lửng và hấp thu toàn bộ nước mưa cùng hơi lạnh trong phòng, cứu Trương Hổ khỏi cái chết vì cóng. Vương Lâm phát hiện đám mây trên hạt châu đã tăng từ 5 lên 7. Sau đó hắn lén đem hạt châu cùng các hồ lô giấu ở khu vực cất sương sớm trên núi; một tháng sau lấy về phát hiện đám mây đã tiến hóa từ 7 lên 9 và bắt đầu mang hạt châu theo sát bên người để nghiên cứu. (@c0001)\n- Vương Lâm đóng kín cửa phòng để làm thí nghiệm, đổ lộ thủy vào một bát đá và cho 'Hạt châu thần bí' vào ngâm qua đêm với hy vọng kích thích xuất hiện đám mây thứ 10. Sáng hôm sau, nước trong bát vơi đi một nửa nhưng đám mây thứ 10 vẫn chưa xuất hiện. Khi uống nhiều lộ thủy, linh khí ngưng tụ vượt tốc độ tiêu tan khiến cơ thể đau nhức, mạch máu nổi căng phồng như sâu xanh khắp người sắp vỡ; hắn kinh hãi nảy ra sáng kiến hít thở ngược (ba dài một ngắn) để giải tỏa linh khí — khởi nguồn của tán công. Quá trình tán công kéo dài một ngày một đêm; xong việc hắn kiệt sức ngã xuống giường, thầm mừng giữ được mạng rồi lăn ra ngủ. Khí độc do tán công phát tán không bị hạt châu hấp thụ mà tự tiêu tan, còn linh khí phát ra thì bị hạt châu hấp thụ. (@c0022)\n- Trải qua hai tháng, Vương Lâm đã nghiên cứu thấu triệt công năng mộng cảnh của hạt châu. Hắn liên tục dùng nó để vào mộng cảnh tu luyện không ngừng nghỉ và uống linh khí tuyền thủy được tạo ra từ hạt châu thay cho ăn uống. Để bảo mật, hắn luôn cất giấu hạt châu cẩn thận vào ngực áo trước khi tiến nhập mộng cảnh để không ai tại Hằng Nhạc phái phát hiện. Vương Lâm đột phá thành công tầng thứ nhất ngưng khí kỳ trong mộng cảnh giới: linh khí lưu động toàn thân, mồ hôi đen có mùi khó chịu tiết ra, tuyền thủy phân giải thay đổi kết cấu cơ thể. Sau đột phá, nhìn cảnh vật trong mộng cảnh thấy các vật sáng ẩn chứa linh khí lưu động như người mù khôi phục thị lực. Trong thực tại, đột phá tầng một đẩy phần lớn tạp chất ra, cải tạo kinh mạch; hắn ra cửa đông xuống hạ du sơn tuyền tắm rửa tẩy sạch tạp chất. (@c0025)\n- Sau khi xử lý xong thi thể một kẻ địch, Vương Lâm cất tiên phù vào túi trữ vật để dành nghiên cứu, rồi lấy 'Hạt châu thần bí' ra tiến vào không gian mộng cảnh. Lần này hắn không dồn hết tinh thần vào thổ nạp mà dành thời gian luyện Dẫn Lực thuật bằng hình nhân cho đến khi thao tác thành công. (@c0027)", "nguon": ["@c0001", "@c0022", "@c0025", "@c0027"]}, {"id": "hat-suong", "name": "Hạt sương", "cn": "", "aliases": ["sương sớm", "lộ thủy"], "category": "phap-bao", "categoryLabel": "Pháp bảo", "phamCap": "", "soHuu": ["vuong-lam"], "blurb": "Chất lỏng/hơi nước tự nhiên ngưng tụ trên bề mặt vật thể, đặc biệt là thạch châu thần bí.", "detail": "Chất lỏng/hơi nước tự nhiên ngưng tụ trên bề mặt vật thể, đặc biệt là thạch châu thần bí. Nguồn gốc quyết định chất lượng: sương đọng trực tiếp trên thạch châu vào sáng sớm tốt nhất, ban đêm thứ hai, thu thập từ vật thể khác kém hơn nhiều. Là chất lỏng tốt nhất để ngâm thạch châu thần bí, vượt trội hơn nước suối, tuyết thủy, mồ hôi và máu. Có vị hơi ngọt, uống rất ngon, mang lại cảm giác thoải mái ấm áp; có mùi thơm dìu dịu khiến toàn thân dễ chịu. Khi cất giữ kín lâu ngày trong hồ lô chôn dưới đất sẽ trở nên đông đặc như bị đông lạnh. Khi đọng trên thạch châu, hơn phân nửa lượng sương bị thạch châu hấp thu biến mất, lượng lưu lại chưa đến một phần mười. Nhược điểm: thu thập tự nhiên quá ít, tốn nhiều thời gian tích cóp và hoàn toàn không thể thu thập vào mùa đông.\n\nDIỄN BIẾN:\n- Vương Lâm uống nước suối ngâm thạch châu thần bí, dù thấy cơ thể ấm áp và hết đau nhức bắp thịt nhưng vẫn nhận định hiệu quả này không thể tốt bằng Hạt sương. (@c0011)\n- Vương Lâm lén nghiên cứu thạch châu, thử ngâm bằng nhiều loại chất lỏng (nước suối, Hạt sương, mồ hôi, máu) và kết luận Hạt sương cho hiệu quả gia tăng đám mây tốt nhất. Hắn phân loại Hạt sương theo nguồn và thời điểm, đựng vào hồ lô nhỏ hoang dại rồi chôn sâu dưới đất ở nơi vắng vẻ, mỗi ngày đều đi thu gom. Hắn phát hiện hơn 9/10 lượng Hạt sương đọng trên thạch châu đã bị nó hấp thu. (@c0012)\n- Vương Lâm lấy hồ lô đựng lộ thủy ra, đổ vào bát đá; lộ thủy chưa được nửa bát, tỏa mùi thơm dìu dịu, dùng ngâm thạch châu thần bí nhằm tạo ra đám mây thứ mười. Sau một đêm ngâm, lượng Hạt sương trong bát vơi đi một nửa. Khi uống nhiều lộ thủy, linh khí ngưng tụ vượt tốc độ tiêu tan khiến cơ thể đau nhức, mạch máu căng phồng, hắn nảy ra cách hít thở ngược để giải tỏa — khởi nguồn của tán công. (@c0022)\n- Dù lộ thủy trong bát chưa vơi hết, thạch châu đã hấp thụ đủ và xuất hiện đám mây thứ mười vào chỗ trống. Vương Lâm thử mọi cách tìm biến đổi (thay nước suối, cắn, nhỏ máu, dùng bát đập) nhưng không thấy gì, nên tiếc hai bình lộ thủy và bực tức ném ngọc đi. (@c0023)\n- Khi tính tìm chất lỏng chứa linh khí mang đi giao dịch hội, Vương Lâm xếp hạng lộ thủy (Hạt sương) tốt nhất nhưng thu được quá ít và mùa đông không có; tuyền thủy thứ hai. Hắn buộc phải chuyển sang thu thập nước tuyết tan (tuyết thủy) làm giải pháp thay thế. (@c0031)", "nguon": ["@c0001", "@c0011", "@c0012", "@c0022", "@c0023", "@c0031"]}, {"id": "ho-lo", "name": "Hồ lô", "cn": "", "aliases": [], "category": "phap-bao", "categoryLabel": "Pháp bảo", "phamCap": "", "soHuu": ["vuong-lam", "ton-truong-lao-ton-dai-tru"], "blurb": "Pháp bảo có nguồn gốc là những quả hồ lô dại mọc leo thành giàn ở khu vực rừng núi tự nhiên quanh Hằng Nhạc phái.", "detail": "Pháp bảo có nguồn gốc là những quả hồ lô dại mọc leo thành giàn ở khu vực rừng núi tự nhiên quanh Hằng Nhạc phái. Ở trạng thái mới hái xuống, hồ lô hoàn toàn là vật bình thường, cuống vẫn còn tươi ương, không chứa chút linh khí nào của thiên địa. Được dùng như vật chứa tự nhiên tiện dụng để đựng nước suối trên núi, sương sớm đọng lại hoặc nước tuyết tan. Khi dùng để chứa nước ngâm cùng hạt châu thần bí, hồ lô trở thành vật chứa ngập tràn linh khí cực kỳ sung túc; nước bên trong giúp phàm nhân uống vào thấy tinh thần thoải mái, tiêu trừ mỏi mệt (dù không hấp thụ được linh khí), còn với tu chân giả dùng để luyện đan dược thì mang lại hiệu quả cực kỳ tốt. Bản thân vỏ hồ lô không có sự bất phàm vĩnh cửu: nếu không có hạt châu duy trì, linh khí bên trong sẽ dần tiêu tán hết trong vòng gần một tháng, khiến nước và bản thân hồ lô quay về trạng thái phàm tục. Khi lưu trữ sương sớm kết hợp năng lượng hạt châu một thời gian, sương sớm bên trong sẽ đông đặc lại như bị đông lạnh. Những chiếc hồ lô mới hái, đựng nước trong thời gian ngắn (vỏ chưa ngấm linh khí quá lâu) có thể qua mặt được không gian mộng cảnh giới, giúp người dùng mang trót lọt hồ lô cùng linh khí tuyền thủy vào bên trong để gia tăng tốc độ tu luyện.\n\nDIỄN BIẾN:\n- Tôn trưởng lão dùng thần thức quét khắp phòng rồi mở bọc hành lý của Vương Lâm, lấy ra hồ lô đựng nước suối, ngửi và đại biến sắc mặt vì nhận ra linh khí cực kỳ sung túc bên trong. Vương Lâm nói dối rằng vớt được ở thượng nguồn suối, nhưng lão vạch trần lời nói dối vì nhận ra cuống hồ lô vẫn còn tươi ương chứng tỏ mới bị bẻ. Lão dọa trục xuất Vương Lâm để ép nói nguồn gốc, sau lại đổi giọng hòa ái đề nghị làm thư đồng (Vương Lâm từ chối), cuối cùng thu hắn làm đệ tử nhằm chiếm trọn các hồ lô để luyện đan tiến tu vi, và quyết giấu việc này khỏi sư huynh đệ. (@c0016)\n- Vương Lâm được sai đi tìm hồ lô nhưng ra suối vốc nước rửa mặt rồi ngồi thổ nạp tu luyện từ sáng tới trưa, trong khi Tôn Đại Trụ nấp trên đại thụ giám sát. Chiều tối, Vương Lâm đi quanh núi tìm đến giàn hồ lô dại, hái một chiếc hồ lô nhỏ tươi mang về dâng, nói trông giống hồ lô cũ. Tôn Đại Trụ không khống chế được, gầm rống mắng rằng lão muốn hồ lô tràn ngập linh khí giống cái cũ chứ không phải hồ lô tươi vô dụng; lão uất nghẹn vì bị đùa giỡn cả ngày, mà chính lão còn ngu xuẩn hái vài cái hồ lô dại mang về. (@c0018)\n- Tôn Đại Trụ cố đổ đầy nước suối vào hồ lô bình thường để nghiên cứu suốt nửa ngày nhưng không thấy tác dụng gì, còn bị vài sư huynh nhìn thấy chế nhạo. Lão đưa cho Vương Lâm một khối hạ phẩm linh thạch vì tin hắn chỉ vô tình nhặt được hồ lô có linh khí. Sau gần một tháng, hồ lô linh khí ban đầu tiêu tán sạch, trở thành đồ bỏ đi; lão suy đoán hồ lô không tự sinh linh khí mà do một biến cố đặc thù, thất vọng nên trục xuất Vương Lâm khỏi chính viện. Vương Lâm lén quay lại nơi cất giấu, mang hạt châu và 3 chiếc hồ lô giấu vào túi trữ vật, mở ra phát hiện sương sớm bên trong đã bị đông đặc. Hắn lên núi hái thêm 4-5 chiếc hồ lô dại mới, chứa đầy linh khí tuyền thủy và thành công mang vào mộng cảnh giới để uống dần, bổ sung linh khí tu luyện lên Ngưng Khí tầng thứ nhất. (@c0019)\n- Sau nửa năm thu thập trên núi, Vương Lâm lấy ra một đống hồ lô từ túi trữ vật, đổ đầy Linh Khí Tuyết Thủy (nước tuyết tan) vào một nửa số hồ lô đó để dự trữ tu luyện. (@c0030)", "nguon": ["@c0016", "@c0018", "@c0019", "@c0030"]}, {"id": "lam-tuyen-thao", "name": "Lam Tuyến Thảo", "cn": "", "aliases": [], "category": "phap-bao", "categoryLabel": "Pháp bảo", "phamCap": "", "soHuu": ["ton-dai-tru"], "blurb": "Là một loại thảo dược.", "detail": "Là một loại thảo dược. Nguồn gốc không đề cập, chỉ biết được trồng trong vườn dược của trưởng lão họ Tôn (Tôn Đại Trụ) thuộc Hằng Nhạc Phái. Khi còn sống thì xanh mượt tràn đầy sức sống.\n\nDIỄN BIẾN:\n- Trưởng lão họ Tôn (Tôn Đại Trụ) trồng mấy nhánh Lam Tuyến Thảo (cùng với Tử Dạ Hoa) ở gần cổng vườn dược bên trong chính viện. Buổi trưa chúng còn xanh mượt tràn đầy sức sống. (@c0011)\n- Lúc Vương Lâm rời đi không lâu, Tôn Đại Trụ chuẩn bị thu dọn thảo dược thì phát hiện mấy nhánh Lam Tuyến Thảo toàn bộ héo rũ (Tử Dạ Hoa đối diện cũng héo nhưng không nghiêm trọng bằng). Nhìn từ bên ngoài, Lam Tuyến Thảo đã mất đi toàn bộ nước nên khô héo, mặc dù bùn đất rất ẩm ướt và môi trường hoàn toàn phù hợp để sinh trưởng. Do Vương Lâm là người duy nhất đến đây vào buổi chiều, Tôn Đại Trụ nghi ngờ Vương Lâm gây ra sự việc này và quyết định đi điều tra. (@c0011)", "nguon": ["@c0011"]}, {"id": "linh-thach", "name": "Linh thạch", "cn": "", "aliases": ["Tiên thạch", "Hạ phẩm linh thạch"], "category": "phap-bao", "categoryLabel": "Pháp bảo", "phamCap": "Hạ phẩm linh thạch", "soHuu": ["ton-dai-tru", "vuong-lam"], "blurb": "Linh thạch (còn gọi Tiên thạch, hoặc phân loại cấp bậc là Hạ phẩm linh thạch) là vật phẩm dành cho người tu chân dùng để hỗ trợ tu luyện, giúp người sử dụng mau chóng đạt tới cảnh giới Ngưng Khí tầng thứ nhất.", "detail": "Linh thạch (còn gọi Tiên thạch, hoặc phân loại cấp bậc là Hạ phẩm linh thạch) là vật phẩm dành cho người tu chân dùng để hỗ trợ tu luyện, giúp người sử dụng mau chóng đạt tới cảnh giới Ngưng Khí tầng thứ nhất. Nguồn không đề cập chi tiết về nơi khai thác hay nguồn gốc hình thành; chỉ biết được các tu chân giả cất giữ trong túi trữ vật mang theo bên người. Về ngoại hình, Linh thạch có vẻ ngoài cực kỳ bình thường, quan sát kỹ cũng thấy chẳng có chỗ nào bất phàm, nhưng khi nắm chắc trong tay người cầm sẽ cảm nhận được một chỗ phi thường khác biệt so với đá tảng thông thường. Công năng là cầm trong tay khi nhắm mắt thổ nạp để cung cấp hỗ trợ tu vi.\n\nDIỄN BIẾN:\n- Vương Lâm thưa chuyện với Tôn Đại Trụ, nhắc lại việc bản thân nghe người ta nói nếu tìm được hồ lô thì sẽ được cho Linh thạch, qua đó hỏi Tôn Đại Trụ xem linh khí là gì. (@c0019)\n- Tôn Đại Trụ sau một hồi ngây người và trầm ngâm, lão cảm thấy hối hận vì trước đó đã bỏ dược vật vào đồ ăn làm ảnh hưởng tư chất của Vương Lâm. Do muốn Vương Lâm nhanh luyện thành Ngưng Khí tầng một để dùng Sưu Hồn thuật, lão đã do dự rồi từ trong túi trữ vật xuất ra một khối Hạ phẩm linh thạch. Lão thầm tính rằng với tư chất kém cộng thêm dược vật cản trở, nếu không dùng thảo dược thì phải mất 30 năm, còn thường xuyên cho ăn dược vật cũng phải tám đến mười năm. (@c0019)\n- Tôn Đại Trụ ném khối hạ phẩm linh thạch này cho Vương Lâm và bảo hắn cầm lấy, giục hắn mau chóng tu luyện tới Ngưng Khí tầng thứ nhất. (@c0019)\n- Vương Lâm vội vàng tiếp nhận lấy khối linh thạch, cáo tạ Tôn Đại Trụ rồi trở về phòng của mình. (@c0019)\n- Tại phòng riêng, Vương Lâm khoanh chân ngồi, quan sát khối Tiên thạch (tức Linh thạch) trong tay. Hắn thấy không có chỗ nào bất phàm nhưng khi nắm chắc thì cảm nhận được sự phi thường. (@c0019)\n- Vương Lâm cầm khối linh thạch, nhắm hai mắt lại và bắt đầu quá trình thổ nạp. Tuy nhiên, sau một đêm trôi qua, trong cơ thể hắn vẫn không hề có dấu hiệu linh khí nhập thể nào. (@c0019)\n- Trước khi truyền linh khí, Tôn Đại Trụ đã xót xa lẩm bẩm rồi lấy thêm mấy khối hạ phẩm linh thạch đặt hai bên Vương Lâm, thầm nghĩ lần này mất tiền vốn lớn và ngày sau ngươi hết thảy sẽ phải trả lại cho ta. Sau khi thất bại, lão vung tay áo quay đầu rời phòng với nét mặt đau lòng vì mất vốn liếng; sau đó hồ lô tiêu tán linh khí khiến lão càng tức giận, gọi Vương Lâm lên răn dạy rồi trục xuất khỏi chính viện. (@c0019)", "nguon": ["@c0019"]}, {"id": "nuoc-suoi", "name": "Nước suối", "cn": "", "aliases": ["Linh khí tuyền thủy", "Tuyền thủy", "Linh khí tuyết thủy", "Tuyết thủy", "Lộ thủy", "Nước sương", "Nước tuyết", "Nước mưa", "Nước sông"], "category": "phap-bao", "categoryLabel": "Pháp bảo", "phamCap": "", "soHuu": ["vuong-lam", "ton-dai-tru-tich-thu-mot-ho-lo"], "blurb": "\"Nước suối\" và các biến thể (sương sớm, nước tuyết, nước mưa, nước sông) vốn là chất lỏng thiên nhiên bình thường, biến thành kỳ trân dị bảo chứa linh khí (\"linh khí tuyền thủy\"/\"linh khí tuyết thủy\") nhờ ngâm hạt châu thần bí (thạch châu).", "detail": "\"Nước suối\" và các biến thể (sương sớm, nước tuyết, nước mưa, nước sông) vốn là chất lỏng thiên nhiên bình thường, biến thành kỳ trân dị bảo chứa linh khí (\"linh khí tuyền thủy\"/\"linh khí tuyết thủy\") nhờ ngâm hạt châu thần bí (thạch châu). Công năng: phàm nhân uống vào thấy ấm áp dào dạt, hết đau nhức cơ bắp, tinh thần phấn chấn; người tu tiên uống vào linh khí hóa thành nhiệt lưu cung cấp không ngừng để tu luyện, có thể thay thế ăn uống. Dùng luyện đan gia tăng hiệu suất. Nếu rót ra khỏi hạt châu để lâu (khoảng 1 tháng) linh khí tiêu tán hết, trở lại nước suối phàm tục. Phân cấp hiệu quả giảm dần: hạt sương sáng sớm trên hạt châu > sương ban đêm > sương thu từ vật khác > nước tuyết tan > nước suối > nước sông > máu và mồ hôi. Khi tu vi lên cao (Ngưng Khí tầng 2) hiệu quả cung cấp linh khí giảm sút, phải uống nhiều hơn hoặc dùng chất lỏng cấp cao hơn. Ngâm tuyền thủy mươi phút là cực hạn, lâu hơn hiệu quả không đổi.\n\nDIỄN BIẾN:\n- Bị phạt gánh nước, Vương Lâm lấy nước từ con suối ở cửa Đông Hằng Nhạc Phái, tìm chỗ không người lắc hạt châu trong nửa thùng nước rồi uống; cơ thể ấm áp, hết đau nhức. Dùng cách này mỗi ngày, sau một tháng càng cường tráng, rút thời gian gánh mười vại từ sáu ngày xuống ba ngày, nhưng vẫn giả mệt mỏi để không ai nghi ngờ. Hiệu quả ngâm nước suối không bằng hạt sương. (@c0011)\n- Vương Lâm thử ngâm hạt châu bằng nhiều loại chất lỏng (sương, nước suối, mồ hôi, máu) để so sánh hiệu quả. Thu thập hồ lô hoang dại đựng sương chôn giấu, chỉ mang theo hồ lô đựng nước suối; dùng uống cho tinh thần phấn chấn. (@c0012)\n- Trong đêm mưa giông, hạt châu hấp thu toàn bộ nước mưa/hơi ẩm trong phòng và sương giá trên người Trương Hổ (đang đông lạnh gần ngừng thở), cứu được Trương Hổ. Vương Lâm quy việc mình vô sự là do thường uống nước suối ngâm sương sớm. (@c0014)\n- Tôn trưởng lão lục soát hành lý Vương Lâm, tịch thu một hồ lô đựng nước suối, phát hiện linh khí cực kỳ sung túc, nghi liên quan tới việc Lam Tuyến Thảo cùng Tử Dạ Hoa héo rũ, nảy lòng tham chiếm đoạt để luyện đan. Vương Lâm nói dối vớt được dưới suối. (@c0016)\n- Tôn Đại Trụ bắt Vương Lâm đi nhặt thêm hồ lô, nhưng chỉ mang về những hồ lô tươi bình thường không tác dụng, khiến lão tức giận. Vương Lâm tự tin về nơi giấu thần bí châu và hồ lô sương sớm. (@c0017)\n- Sau gần một tháng, linh khí trong hồ lô nước suối của Tôn Đại Trụ tiêu tán hết, trở lại nước suối bình thường. Lão thất vọng, đoán hồ lô phải trải qua biến hóa nào đó. (@c0019)\n- Vương Lâm bị trục xuất khỏi chính viện, vui mừng vì có thể tự do dùng nước suối ngâm hạt châu tu luyện; tin ba hồ lô sương sớm giấu kín có linh khí đậm đặc giúp tu luyện hơn cả đan dược. (@c0020)\n- Vương Lâm đổ lộ thủy vào bát đá định ngâm hạt châu chờ đám mây thứ 10 nhưng nước bốc hơi nhanh. Uống nhiều lộ thủy khiến linh khí ngưng tụ vượt tốc độ tiêu tan, cơ thể đau nhức, mạch máu căng phồng; hắn nảy sáng kiến hít thở ngược (ba dài một ngắn) để giải tỏa — khởi nguồn của tán công. (@c0022)\n- Vương Lâm mang tuyền thủy về phòng khóa cửa, uống ngụm lớn lấy nhiệt lưu rồi vào Mộng cảnh giới. Nhận ra trong mộng không có linh khí; lần này dù tuyền thủy tiêu tan vẫn giữ lại một tia linh khí trong cơ thể, mang lại tin tưởng lớn. Dùng hồ lô dại chứa tuyền thủy duy trì tu luyện liên tục, đang tiến sát tầng một ngưng khí kỳ. (@c0024)\n- Trong 2 tháng thực tế (tương đương 1 năm trong Mộng cảnh giới), Vương Lâm điên cuồng uống nước suối linh khí thay ăn uống để đả tọa thổ nạp, thành công đột phá Ngưng Khí tầng 1; tuyền thủy phân giải thay đổi kết cấu cơ thể. Sau đột phá ra hạ du sơn tuyền tắm rửa tẩy tạp chất. (@c0025)\n- Đạt Ngưng Khí tầng 2, hiệu quả linh khí tuyền thủy giảm sút. Vương Lâm dùng Dẫn Lực Thuật và hỏa cầu làm tan tuyết tạo \"Linh Khí Tuyết Thủy\" (hiệu quả cao hơn nước suối), lấp đầy hồ lô nước tuyết; chuẩn bị 100 giọt Linh Khí Tuyền Thủy mang đi giao dịch hội. Nghiên cứu hạt châu: ngâm tuyền thủy mươi phút là cực hạn. (@c0031)\n- Trong 10 ngày trước giao dịch, Vương Lâm uống hết số nước suối cũ để hóa thành linh khí trong cơ thể. (@c0032)\n- Tại giao dịch hội, Vương Lâm dùng hơn 100 giọt Linh Khí Tuyền Thủy đổi với nhị sư huynh (nam tử mặc tử y) lấy ngọc giản khẩu quyết Ngưng Khí kỳ tầng 4-9. Đối phương ép lấy toàn bộ chất lỏng còn lại (bình nhỏ vài chục giọt) và dặn nếu có thêm thì đến hậu sơn tìm — lời thâm độc bóc lộ Vương Lâm trước đám đông. Vương Lâm phải dùng Dẫn Lực Thuật dán tiên phù chạy trốn. (@c0033)\n- Chưởng môn chuyển nội môn đệ tử ra Hậu Sơn bế quan. Vương Lâm chọn một huyệt động, hài lòng vì tu luyện tự do; do động không có nước nên quyết định dùng nguồn nước tuyết (tuyết thủy) đã tích trữ trong túi trữ vật. Cách tu luyện đặc thù của hắn chủ yếu dựa vào linh khí dịch thể. (@c0035)", "nguon": ["@c0009", "@c0011", "@c0012", "@c0014", "@c0016", "@c0017", "@c0019", "@c0020", "@c0022", "@c0024", "@c0025", "@c0031", "@c0032", "@c0033", "@c0035", "@c0037", "@c0039"]}, {"id": "sach-cong-phap-tu-tien", "name": "Sách công pháp tu tiên", "cn": "", "aliases": ["Ngưng khí tam thiên", "Tam Thiên ngưng khí", "quyển sách được đóng bằng chỉ nhỏ", "khẩu quyết"], "category": "phap-bao", "categoryLabel": "Pháp bảo", "phamCap": "công pháp cơ bản dành cho đệ tử nội môn (Ngưng Khí tam thiên, ba tầng)", "soHuu": ["vuong-lam"], "blurb": "Cuốn sách chứa các phương pháp, khẩu quyết và pháp thuật tu tiên cơ bản dành cho đệ tử nội môn Hằng Nhạc phái, do Tôn Đại Trụ cấp cho Vương Lâm cùng đồng phục và túi trữ vật làm nền tảng tu đạo.", "detail": "Cuốn sách chứa các phương pháp, khẩu quyết và pháp thuật tu tiên cơ bản dành cho đệ tử nội môn Hằng Nhạc phái, do Tôn Đại Trụ cấp cho Vương Lâm cùng đồng phục và túi trữ vật làm nền tảng tu đạo. Công pháp tên 'Ngưng Khí tam thiên' gồm ba tầng, là công pháp cơ bản nhất; Ngưng Khí kỳ có mười lăm tầng, phải tu tới tầng thứ ba mới được xem tâm pháp phía sau. Sách dạy Ngưng Khí là thổ nạp thiên địa linh khí tích lũy vào cơ thể, thay đổi thân phàm làm nền tảng, đồng thời khảo nghiệm tư chất — linh căn sung túc hấp thụ nhanh, tư chất kém cả đời không quá ba tầng. Phương pháp hô hấp 'một ngắn ba dài' (trái với bình thường) để hấp thụ nhanh nhất; lần đầu hít thở có cảm giác như côn trùng bò là dấu hiệu linh khí nhập thể. Ngưng Khí kỳ 15 tầng, trừ tầng 1, 14 tầng còn lại cần khẩu quyết khai phá; việc mở tầng phụ thuộc thiên tư, linh khí, kỳ ngộ. Sách còn ghi ba loại pháp thuật cơ bản mà người tu tiên đạt tầng thứ nhất Ngưng Khí kỳ có thể dùng: 'Dẫn lực thuật' (giai đoạn nền tảng của tiên thuật khu sử phi kiếm), 'Hoả diễm cầu' (tiên thuật tấn công cơ bản), 'Địa liệt thuật' (tiên thuật liên quan đến mặt đất). Về sau khẩu quyết được cung cấp lên đến tầng thứ chín Ngưng Khí kỳ.\n\nDIỄN BIẾN:\n- Khi Tôn Đại Trụ nhận Vương Lâm làm đệ tử nội môn, lão ném cho hắn túi trữ vật đánh dấu thân phận. Khi đổ đồ vật trong túi ra, Vương Lâm tìm thấy 'Sách công pháp tu tiên' (quyển sách nhỏ đóng bằng chỉ), kích động mở trang đầu ra xem vì rốt cuộc đã được tu tiên. Hắn ghi nhớ ba tầng tâm pháp, thử thổ nạp cả đêm theo cách hô hấp 'một ngắn ba dài' nhưng không có cảm giác linh khí nhập thể, thậm chí gần ngạt thở; đến sáng ra dược viên mới thoáng cảm nhận được côn trùng bò thì bị sư phụ quát đuổi. Vương Lâm ý thức rõ mình tư chất kém: sách công pháp vốn dành cho người tư chất đầy đủ, nên thổ nạp cả đêm không hiệu quả, nhưng không tức giận mà kiên trì tiếp tục. (@c0017)\n- Sau quá trình rèn luyện Dẫn lực thuật trong không gian mộng cảnh, khi tỉnh lại ở thực tại, Vương Lâm uống nước suối và chờ linh khí toàn thân sung túc rồi hít sâu, nhớ lại nội dung của 'Sách công pháp tu tiên' để bắt đầu tiến hành thổ nạp. Vương Lâm mặc niệm khẩu quyết tầng hai gây cảm giác chua xót, tê dại, đau nhức rồi trở lại bình thường khi ngồi xuống. Hắn tự đặt tiêu chuẩn cho Dẫn Lực thuật: luyện đến mức tùy tâm sở dục, mười lần thành công cả mười (hiện xác suất chỉ 30-40%); rút ra việc nóng vội mở tầng hai là vô ích vì linh khí chưa đủ, quyết định tu luyện tầng một đến đỉnh phong rồi mới mở tầng hai để xác suất cao hơn. (@c0027)\n- Mạch truyện tiến triển cho thấy Vương Lâm đã có được khẩu quyết của 'Sách công pháp tu tiên' lên đến Ngưng Khí kỳ tầng thứ chín, nhờ đó hắn hoàn toàn an tâm, suốt ngày ru rú trong nhà để chuyên tâm tu luyện. Vương Lâm còn đề phòng chỗ ở tạp vụ 'lắm thầy nhiều ma' không thích hợp tu luyện, nên muốn kiếm cớ xuống núi tìm chỗ yên tĩnh tiềm tu, nhưng thầm than chuyện ra ngoài tu luyện không khả thi nên quyết định thừa dịp tập huấn để tìm cơ hội tu luyện. (@c0034)", "nguon": ["@c0017", "@c0027", "@c0034"]}, {"id": "tien-phu", "name": "Tiên phù", "cn": "", "aliases": ["Thiên Lý Phù", "Tham Thân tiên phù"], "category": "phap-bao", "categoryLabel": "Pháp bảo", "phamCap": "Cấp thấp (bùa chú pháp thuật phổ thông); có biến thể đặc biệt mang linh khí cường đại", "soHuu": ["vuong-lam", "vuong-lam", "vuong-lam", "vuong-lam"], "blurb": "Tiên phù là một loại bùa chú pháp thuật cấp thấp của giới tu tiên, bề ngoài là một tờ giấy màu vàng nhìn giống giấy bình thường.", "detail": "Tiên phù là một loại bùa chú pháp thuật cấp thấp của giới tu tiên, bề ngoài là một tờ giấy màu vàng nhìn giống giấy bình thường. Do Hằng Nhạc phái cấp phát cho đệ tử ký danh khi về thăm người thân, nhằm để đệ tử thể hiện tiên gia pháp thuật trước phàm nhân, hấp dẫn thêm trẻ em đến trắc thí nhập môn. Cách dùng đơn giản: dán lên đùi/chân là kích hoạt, giúp phàm nhân hoặc người tu vi thấp đề cao tốc độ di chuyển. Loại thông thường (Thiên Lý Phù) dùng được hai lần. Các tấm có thể dán chồng lên nhau; dùng liền mấy chục tấm thì tốc độ tăng vô cùng nhanh. Tuy là đồ cấp thấp nhưng rất có giá trị quy đổi, đệ tử thường tích góp để giao dịch đổi đồ vật hoặc mua đan dược. Tồn tại một biến thể đặc biệt giống hệt Tham Thân tiên phù nhưng ẩn chứa linh khí vượt xa và toát hơi thở nguy hiểm, được khẳng định là một bảo bối.\n\nDIỄN BIẾN:\n- Vương Lâm được Tôn trưởng lão cấp một tờ Thiên Lý Phù (dùng được hai lần) cùng kỳ hạn ba ngày để về thăm nhà. Tờ giấy vàng từ cửa sổ bay ra rơi xuống chân, hắn nhặt lên cất vào ngực áo. Vì chưa tìm được cách điều chỉnh tốc độ, hắn dự định chạy đi suốt đêm cho kịp sinh nhật cha. Cùng lúc, hắn biết được việc nhiều đệ tử tích góp tiên phù để giao dịch. (@c0012)\n- Vương Lâm được Trương Hổ tặng một cuộn giấy vàng tiên phù đặc biệt. Quan sát kỹ, hắn nhận ra nó chứa linh khí vượt xa bình thường và toát hơi thở nguy hiểm. Cảnh giác cộng thêm bài học suýt chết khi uống nước sương, hắn không dám dùng thử mà cất vào túi trữ vật để dành sau này tìm hiểu. (@c0027)\n- Vương Lâm gộp toàn bộ số tiên phù bình thường (cứ một trăm cái thành một phần) và giao cho Vương Hạo. Vương Hạo hai mắt sáng lên, nhận lấy cất vào túi trữ vật để chuẩn bị đi giao dịch hội nửa tháng sau. Số tiên phù này được dùng như tiền tệ để mua đan dược. (@c0028)\n- Sau khi giao dịch hội kết thúc, Vương Lâm không rời ngay mà ngầm dán hơn mười rồi mấy chục tấm tiên phù lên chân, phóng đi như lợi kiếm biến mất. Hiệu ứng chồng lên nhau giúp tốc độ trở nên nhanh vô cùng. Mấy kẻ có ý đồ với chất lỏng muốn đuổi nhưng không kịp; các đệ tử tu vi cao cũng không dám trắng trợn đuổi giết vì sợ Phương sư phụ. Đây là phòng bị, hắn trở về Hằng Nhạc phái an toàn. (@c0033)", "nguon": ["@c0012", "@c0027", "@c0028", "@c0033"]}, {"id": "tui-tru-vat", "name": "Túi trữ vật", "cn": "", "aliases": [], "category": "phap-bao", "categoryLabel": "Pháp bảo", "phamCap": "", "soHuu": ["vuong-lam", "ton-dai-tru"], "blurb": "Vật dụng của giới tu tiên dùng để chứa đựng đồ vật, đồng thời được dùng như vật đánh dấu định danh thân phận của đệ tử nội môn; do môn phái phân phát cho đệ tử (nguồn không đề cập ai luyện chế).", "detail": "Vật dụng của giới tu tiên dùng để chứa đựng đồ vật, đồng thời được dùng như vật đánh dấu định danh thân phận của đệ tử nội môn; do môn phái phân phát cho đệ tử (nguồn không đề cập ai luyện chế). Là chiếc túi dẹt nhỏ màu xám, bề ngoài không có gì khác lạ. Bên trong có không gian chứa đồ, đựng được nhiều loại vật phẩm như quần áo, công pháp tu tiên, tiên phù, linh thạch; sức chứa tương đối lớn, đủ để chứa vừa cả một thi thể người trưởng thành. Người dùng có thể cầm túi hướng mặt xuống đất rồi trút để đổ hết đồ ra, hoặc chủ động điều khiển xuất đồ từ trong túi ra.\n\nDIỄN BIẾN:\n- Tôn Đại Trụ sau khi nhận Vương Lâm làm đồ đệ đã ném cho hắn một chiếc Túi trữ vật dẹt dẹt, dặn dò đây là vật đánh dấu thân phận đệ tử nội môn, bên trong để sẵn một ít quần áo và công pháp tu tiên. Vương Lâm cầm túi vào phòng (chỉ có một cái giường nhỏ), ngồi xuống giường, hướng mặt túi xuống đất đổ hết đồ ra: một bộ y phục hồng sắc của đệ tử nội môn và một quyển sách nhỏ đóng bằng chỉ, trang đầu viết 'Ngưng Khí tam thiên'. (@c0017)\n- Khi Vương Lâm thắc mắc không biết linh khí là gì, Tôn Đại Trụ do dự một chút rồi từ trong Túi trữ vật cá nhân của mình xuất ra một khối hạ phẩm linh thạch, ném cho Vương Lâm để hắn cầm lấy mau chóng tu luyện. (@c0019)\n- Sau khi Lưu sư huynh bị giết chết, Vương Lâm nhận thấy không gian trong Túi trữ vật đủ lớn để chứa một thi thể. Nhằm giúp Trương Hổ phi tang và tránh sự truy xét của môn phái, hắn cất thi thể Lưu sư huynh vào Túi trữ vật, lau sạch vết máu trong phòng, lặng lẽ vào núi tìm một khe rồi ném thi thể xuống. Sau khi trở về phòng, hắn lấy cuộn giấy vàng (tiên phù) của Trương Hổ ra xem xét; do cảm nhận hơi thở nguy hiểm và luôn cảnh giác với đồ của tiên nhân, hắn không dám dùng bừa mà cất tiên phù vào lại Túi trữ vật để dành sau này tìm hiểu. (@c0027)", "nguon": ["@c0017", "@c0019", "@c0027"]}]};
